import React, { useEffect, useState } from 'react';
import { get, post, put, remove } from '../api';

const emptyRhyme = {
  title: '',
  youtubeUrl: '',
  isThisGurbani: false,
  ageGroup: '',
  isActive: true,
};

const RhymesList = () => {
  const [rhymes, setRhymes] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [workingRhyme, setWorkingRhyme] = useState(emptyRhyme);
  const [editingId, setEditingId] = useState(null);
  const [showForm, setShowForm] = useState(false);
  const [actionError, setActionError] = useState(null);
  const [successMessage, setSuccessMessage] = useState(null);

  const loadRhymes = async () => {
    setLoading(true);
    setError(null);
    try {
      const response = await get('/api/admin-lists/rhymes');
      setRhymes(response.data);
    } catch (err) {
      console.error(err);
      setError('Unable to load rhymes.');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    loadRhymes();
  }, []);

  const handleRefresh = () => {
    loadRhymes();
  };

  const handleEdit = (rhyme) => {
    setEditingId(rhyme.id);
    setShowForm(true);
    setWorkingRhyme({
      title: rhyme.title || '',
      youtubeUrl: rhyme.youtubeUrl || '',
      isThisGurbani: rhyme.isThisGurbani || false,
      ageGroup: rhyme.ageGroup || '',
      isActive: rhyme.isActive,
    });
    setActionError(null);
    setSuccessMessage(null);
  };

  const handleCreate = () => {
    setEditingId(null);
    setWorkingRhyme(emptyRhyme);
    setShowForm(true);
    setActionError(null);
    setSuccessMessage(null);
  };

  const handleCancel = () => {
    setShowForm(false);
    setEditingId(null);
    setWorkingRhyme(emptyRhyme);
    setActionError(null);
    setSuccessMessage(null);
  };

  const handleSubmit = async () => {
    setActionError(null);
    setSuccessMessage(null);

    try {
      if (editingId) {
        await put(`/api/admin-lists/rhymes/${editingId}`, workingRhyme);
        setSuccessMessage('Rhyme updated successfully.');
      } else {
        await post('/api/admin-lists/rhymes', workingRhyme);
        setSuccessMessage('Rhyme created successfully.');
      }
      await loadRhymes();
      setEditingId(null);
      setWorkingRhyme(emptyRhyme);
      setShowForm(false);
    } catch (err) {
      console.error(err);
      setActionError('Unable to save rhyme.');
    }
  };

  const handleDelete = async (id) => {
    setActionError(null);
    setSuccessMessage(null);
    try {
      await remove(`/api/admin-lists/rhymes/${id}`);
      setSuccessMessage('Rhyme deleted successfully.');
      await loadRhymes();
    } catch (err) {
      console.error(err);
      setActionError('Unable to delete rhyme.');
    }
  };

  const tableStyle = {
    width: '100%',
    minWidth: 920,
    borderCollapse: 'collapse',
    fontSize: 14,
    color: '#1f2937',
  };

  const headerStyle = {
    background: '#f8fafc',
    borderBottom: '2px solid #cbd5e1',
    textAlign: 'left',
    padding: '12px 10px',
    fontWeight: 600,
    fontSize: 13,
    color: '#111827',
  };

  const cellStyle = {
    borderBottom: '1px solid #e5e7eb',
    padding: '10px',
    verticalAlign: 'top',
    whiteSpace: 'normal',
  };

  const buttonStyle = {
    padding: '8px 14px',
    borderRadius: 5,
    border: '1px solid #cbd5e1',
    background: '#ffffff',
    cursor: 'pointer',
  };

  const inputStyle = {
    width: '100%',
    padding: '8px 10px',
    border: '1px solid #d1d5db',
    borderRadius: 4,
    fontSize: 13,
  };

  return (
    <div>
      <div style={{ marginBottom: 14, display: 'flex', flexWrap: 'wrap', gap: 8 }}>
        <button onClick={handleRefresh} disabled={loading} style={buttonStyle}>
          Refresh
        </button>
        <button onClick={handleCreate} style={buttonStyle}>
          Add New
        </button>
      </div>
      {successMessage && <p style={{ color: 'green' }}>{successMessage}</p>}
      {actionError && <p style={{ color: 'red' }}>{actionError}</p>}
      {loading && <p>Loading gurbani...</p>}
      {error && <p style={{ color: 'red' }}>{error}</p>}
      {!loading && !error && (
        <div style={{ overflowX: 'auto' }}>
          <table style={tableStyle}>
            <thead>
              <tr>
                <th style={headerStyle}>Gurbani/Jiwani/History</th>
                <th style={headerStyle}>Youtube Link</th>
                <th style={headerStyle}>Is This Gurbani</th>
                <th style={headerStyle}>Age Group</th>
                <th style={headerStyle}>Actions</th>
              </tr>
            </thead>
            <tbody>
              {rhymes.map((rhyme, index) => (
                <tr key={rhyme.id} style={{ backgroundColor: index % 2 === 0 ? '#ffffff' : '#f8fafc' }}>
                  <td style={cellStyle}>{rhyme.title}</td>
                  <td style={cellStyle}>
                    {rhyme.youtubeUrl ? (
                      <a href={rhyme.youtubeUrl} target="_blank" rel="noopener noreferrer">
                        Link
                      </a>
                    ) : (
                      'None'
                    )}
                  </td>
                  <td style={cellStyle}>{rhyme.isThisGurbani ? 'Yes' : 'No'}</td>
                  <td style={cellStyle}>{rhyme.ageGroup || 'None'}</td>
                  <td style={cellStyle}>
                    <button onClick={() => handleEdit(rhyme)} style={{ ...buttonStyle, marginRight: 8 }}>
                      Edit
                    </button>
                    <button onClick={() => handleDelete(rhyme.id)} style={buttonStyle}>
                      Delete
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}
      {showForm && (
        <div style={{ marginTop: 24, maxWidth: 640, background: '#ffffff', border: '1px solid #e5e7eb', borderRadius: 8, padding: 16 }}>
          <h3 style={{ marginTop: 0 }}>{editingId ? 'Edit Gurbani/Jiwani/History' : 'Add Gurbani/Jiwani/History'}</h3>
          <div style={{ marginBottom: 8 }}>
            <label style={{ display: 'block', marginBottom: 4 }}>Gurbani/Jiwani/History</label>
            <input
              type="text"
              value={workingRhyme.title}
              onChange={(e) => setWorkingRhyme({ ...workingRhyme, title: e.target.value })}
              style={inputStyle}
            />
          </div>
          <div style={{ marginBottom: 8 }}>
            <label style={{ display: 'block', marginBottom: 4 }}>Youtube Link</label>
            <input
              type="text"
              value={workingRhyme.youtubeUrl}
              onChange={(e) => setWorkingRhyme({ ...workingRhyme, youtubeUrl: e.target.value })}
              style={inputStyle}
            />
          </div>
          <div style={{ marginBottom: 8 }}>
            <label style={{ display: 'inline-flex', alignItems: 'center' }}>
              <input
                type="checkbox"
                checked={workingRhyme.isThisGurbani}
                onChange={(e) => setWorkingRhyme({ ...workingRhyme, isThisGurbani: e.target.checked })}
                style={{ marginRight: 8 }}
              />
              Is This Gurbani
            </label>
          </div>
          <div style={{ marginBottom: 8 }}>
            <label style={{ display: 'block', marginBottom: 4 }}>Age Group</label>
            <input
              type="text"
              value={workingRhyme.ageGroup}
              onChange={(e) => setWorkingRhyme({ ...workingRhyme, ageGroup: e.target.value })}
              style={inputStyle}
            />
          </div>
          <div style={{ marginBottom: 12 }}>
            <label style={{ display: 'inline-flex', alignItems: 'center' }}>
              <input
                type="checkbox"
                checked={workingRhyme.isActive}
                onChange={(e) => setWorkingRhyme({ ...workingRhyme, isActive: e.target.checked })}
                style={{ marginRight: 8 }}
              />
              Active
            </label>
          </div>
          <button onClick={handleSubmit} style={{ ...buttonStyle, marginRight: 8 }}>
            Save
          </button>
          <button onClick={handleCancel} style={buttonStyle}>
            Cancel
          </button>
        </div>
      )}
    </div>
  );
};

export default RhymesList;
